import typing
if typing.TYPE_CHECKING:
  pass
import py4godot.classes.IterateIK3D as py4godot_iterateik3d 
from py4godot.wrappers.wrappers import CPPCCDIK3DWrapper


class CCDIK3D(py4godot_iterateik3d.IterateIK3D):
  r'''
		`CCDIK3D` is rotation based IK, enabling fast and effective tracking even with large joint rotations. It's especially suitable for chains with limitations, providing smoother and more stable target tracking compared to `FABRIK3D`.
		The resulting twist around the forward vector will always be kept from the previous pose.
		**Note:** When the target is close to the root, it can cause unnatural movement, including joint flips and oscillations.
	'''

  @staticmethod
  def constructor():
    class_ = CCDIK3D.construct_without_init()
    class_._ptr = constructor(181,0, ())
    return class_
  @staticmethod
  def new():
    class_ = CCDIK3D.construct_without_init()
    class_._ptr = constructor(181,0, ())
    return class_
  def __init__(self):
    self._ptr =  CPPCCDIK3DWrapper()
    self.casted_from = None
    if c_utils.shouldCreateObject:
      self._ptr = constructor(181,0, ())


  def generate_wrapper(self):
    return CPPCCDIK3DWrapper()
  def init_signals(self):
    super().init_signals()

  @staticmethod
  def construct_without_init():
    cls = CCDIK3D.__new__(CCDIK3D)
    cls.shouldBeDeleted = True
    cls.casted_from = None
    cls.constructed_from_python = False
    cls.init_signals()
    return cls
  @staticmethod
  def get_type():
    return 'CCDIK3D'

  def __del__(self):
    pass
  @staticmethod
  def cast(other:'Object'):
    assert other != None # Object to be casted must not be None
    cls = CCDIK3D.construct_without_init()
    cls._ptr = CPPCCDIK3DWrapper()
    cls._ptr_before = other._ptr # Save pointer
    cls._ptr.copy_gdowner(cls._ptr_before)
    return cls
  @staticmethod
  def cast_without_reference(other: 'Object'):
    assert other != None # Object to be casted must not be None
    cls = CCDIK3D.construct_without_init()
    cls._ptr = CPPCCDIK3DWrapper()
    cls._ptr_before = other._ptr # Save pointer
    cls._ptr.copy_gdowner(cls._ptr_before)
    return cls


register_cast_function('CCDIK3D', CCDIK3D.cast)
register_class('CCDIK3D', CCDIK3D)
